import React, { useEffect, useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Case } from '../data/cases';

interface OpeningAnimationProps {
  caseData: Case;
  onComplete: (resultKey: string) => void;
}

const OpeningAnimation: React.FC<OpeningAnimationProps> = ({ caseData, onComplete }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isSlowing, setIsSlowing] = useState(false);
  const intervalRef = useRef<NodeJS.Timeout>();
  const slowTimerRef = useRef<NodeJS.Timeout>();

  // Берем до 30 игр из кейса (если меньше, дублируем)
  const games = caseData.games;
  const totalGames = games.length;

  // Создаем массив для прокрутки: повторяем игры, чтобы хватило на 50+ шагов
  const scrollItems = Array(50).fill(0).flatMap(() => games).slice(0, 60);

  useEffect(() => {
    // Быстрая прокрутка (5 кадров в секунду)
    intervalRef.current = setInterval(() => {
      setCurrentIndex(prev => (prev + 1) % scrollItems.length);
    }, 100); // 100ms = 10fps

    // Через 2 секунды начинаем замедление
    const slowTimer = setTimeout(() => {
      setIsSlowing(true);
      clearInterval(intervalRef.current);

      // Замедленная прокрутка
      let speed = 200;
      const slowInterval = setInterval(() => {
        setCurrentIndex(prev => (prev + 1) % scrollItems.length);
        speed += 50; // увеличиваем интервал
        if (speed > 800) {
          clearInterval(slowInterval);
          // Останавливаемся на случайном индексе, но не показываем игру
          setTimeout(() => {
            // Генерируем ключ
            const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
            const segment = () => Array(5).fill(0).map(() => chars[Math.floor(Math.random() * chars.length)]).join('');
            const fakeKey = `${segment()}-${segment()}-${segment()}-${segment()}-${segment()}`;
            onComplete(fakeKey);
          }, 300);
        }
      }, speed);

      slowTimerRef.current = slowInterval;
    }, 2000);

    return () => {
      clearInterval(intervalRef.current);
      clearTimeout(slowTimer);
      clearInterval(slowTimerRef.current);
    };
  }, []);

  return (
    <div className="opening-container">
      <div className="scroll-window">
        <motion.div
          className="scroll-content"
          animate={{ x: -currentIndex * 120 }} // сдвигаем на ширину иконки
          transition={{ type: 'tween', ease: 'linear', duration: 0.1 }}
        >
          {scrollItems.map((game, idx) => (
            <div key={idx} className="scroll-item">
              <img src={game.bannerUrl} alt={game.name} />
              <span>{game.name.slice(0, 15)}...</span>
            </div>
          ))}
        </motion.div>
      </div>
      <div className="opening-overlay">
        <div className="glow" />
      </div>
    </div>
  );
};

export default OpeningAnimation;
